import sys
import json
import asyncio
from mcp_graph_server_source import build_server

async def main():
    if len(sys.argv) < 2:
        print("Usage: python run_graph_tool.py <tool_name> [arguments_json]")
        sys.exit(1)

    tool_name = sys.argv[1]
    args = {}
    if len(sys.argv) > 2:
        try:
            args = json.loads(sys.argv[2])
        except Exception as e:
            print("Failed to parse arguments JSON:", e)
            sys.exit(1)

    mcp = build_server()

    # We need to run inside the event loop if FastMCP's call_tool is async, 
    # but FastMCP.call_tool is actually a coroutine in some versions, or synchronous.
    # Let's check if call_tool is async.
    import inspect
    is_coro = inspect.iscoroutinefunction(mcp.call_tool)

    try:
        if is_coro:
            res = await mcp.call_tool(tool_name, args)
        else:
            res = mcp.call_tool(tool_name, args)
        print(json.dumps(res, indent=2, default=str))
    except Exception as e:
        print("Error executing tool:", e)
        sys.exit(1)

if __name__ == "__main__":
    asyncio.run(main())

